#include <stdio.h>

long long fastPower(long long base, int exponent) {
    long long result = 1;
    while (exponent) {
        if (exponent & 1) result *= base;
        base *= base;
        exponent >>= 1;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long base, exponent;
        scanf("%lld %d", &base, &exponent);
        printf("%lld\n", fastPower(base, exponent));
    }
    return 0;
}

