const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout
});

let i = 0;
let T;
let input = [];
readline.on('line', line => {
  if (i === 0) {
    T = parseInt(line);
  } else {
    input.push(line.split(' ').map(Number));
  }
  i++;
  if (i > T) {
    readline.close();
    main();
  }
});

function fastPower(base, exponent) {
  let result = 1n;
  let b = BigInt(base);
  let e = BigInt(exponent);
  while (e > 0n) {
    if (e & 1n) result *= b;
    b *= b;
    e >>= 1n;
  }
  return result;
}

function main() {
  for (let i = 0; i < T; i++) {
    let [base, exponent] = input[i];
    console.log(fastPower(base, exponent).toString());
  }
}
